const raw = $input.first().json;

let content = raw.choices?.[0]?.message?.content;
if (!content) throw new Error('OpenAI content boş: ' + JSON.stringify(raw).slice(0, 300));

console.log('[JSON Parse] raw content:', String(content).slice(0, 500));

let cleaned = typeof content === 'string' ? content.trim() : JSON.stringify(content);

// 1. Markdown code block temizle
cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

// 2. İlk { ile son } arasındaki JSON'u çıkar (başında/sonunda metin olsa da)
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
if (start !== -1 && end !== -1 && end > start) {
  cleaned = cleaned.slice(start, end + 1);
}

console.log('[JSON Parse] cleaned:', cleaned.slice(0, 300));

const response = JSON.parse(cleaned);

const evraklar = response.evraklar || response.documents || response.docs || [];
if (!evraklar.length) throw new Error('evraklar boş. response: ' + JSON.stringify(response).slice(0, 300));

const applicationId = $('Webhook').first().json.body.application_id;

return evraklar.map(evrak => ({
  json: {
    application_id: applicationId,
    doc_name: evrak.doc_name,
    delivery_type: evrak.delivery_type,
    description: evrak.description || '',
    status: 'pending'
  }
}));
